head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 4,
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL2100000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	dmaSearchParam.set("strtDt", utilLib.getCurrentDate("yyyy"));
	// 그리드 데이터 조회
	scwin.btnInqire_onclick();

	//ecsLib.setChartResizeObserver(this);
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");

	if (String(strtDate).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;

	var option = {
		action : "cl/reccer/retrieve-rec-cer.do"
			+ queryString,
		method : "get",
		resData : dltRecCerList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	scwin.setRecChart();
	scwin.setCerChart();
};

//============================================================================================
// 차트
//============================================================================================
/**
 * REC 정산총액 차트 데이터 조회 콜백
 */
scwin.setRecChart = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerRec";
	rMateChartH5.create($p.id + "chartRec", grpChartRec.getID(), chartVars, "100%", "100%");
};

/**
 * 합산값 라벨 설정
 * @param {
 	index : index,
 	data : 데이터,
 	value : 값
 }
 * @return 라벨 내용
 */
scwin.recTotalLabelHandler = function(index, data, value) {
	return ecsLib.dsplZeroFrmt(value);
};

/**
 * REC 정산총액 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerRec = function(id) {
	var recCerList = dltRecCerList.getAllJSON();
	recCerList.forEach(obj => {
		obj["month"] = Number(obj.ym.slice(-2)) + "월"
		obj.smlhp = Number(ecsLib.dsplZeroFrmt(obj.smlhp / 1000 / 1000, 0).replaceAll(",", "")) || 0;
		obj.snpw = Number(ecsLib.dsplZeroFrmt(obj.snpw / 1000 / 1000, 0).replaceAll(",", "")) || 0;
		obj.wdpw = Number(ecsLib.dsplZeroFrmt(obj.wdpw / 1000 / 1000, 0).replaceAll(",", "")) || 0;
	});
	var chartData = recCerList;

	var maxData = recCerList.reduce((max, obj) => Math.max(max, obj.smlhp, obj.snpw, obj.wdpw), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="REC 정산총액" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend position="bottom" labelPlacement="right" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="month" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="백만"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="stacked" showTotalLabel="true" totalLabelJsFunction="'+ $p.id + 'scwin.recTotalLabelHandler">'
		+ '		<series>'
		+ '			<Column2DSeries font-weight="bold" yField="smlhp" displayName="소수력(백만)">'
		+ '				<fill>'
		+ '					<SolidColor color="#FFAECC" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			<Column2DSeries font-weight="bold" yField="snpw" displayName="태양광(백만)">'
		+ '				<fill>'
		+ '					<SolidColor color="#FEC7DD" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			<Column2DSeries font-weight="bold" yField="wdpw" displayName="풍력(백만)">'
		+ '				<fill>'
		+ '					<SolidColor color="#CDB4DB" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '		</series>'
		+ '			</Column2DSet>'
		+ '		</series>'
		+ '	<verticalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false"/>'
		+ '	</verticalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * CER 정산총액 차트 데이터 조회 콜백
 */
scwin.setCerChart = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCer";
	rMateChartH5.create($p.id + "chartCer", grpChartCer.getID(), chartVars, "100%", "100%");
};

/**
 * CER 정산총액 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerCer = function(id) {
	var recCerList = dltRecCerList.getAllJSON();
	recCerList.forEach(obj => {
		obj["month"] = Number(obj.ym.slice(-2)) + "월"
		obj.tdpw = Number(ecsLib.dsplZeroFrmt(obj.tdpw / 1000 / 1000, 0).replaceAll(",", "")) || 0;
		obj.ovsea = Number(ecsLib.dsplZeroFrmt(obj.ovsea / 1000 / 1000, 0).replaceAll(",", "")) || 0;
	});
	var chartData = recCerList;

	var maxData = recCerList.reduce((max, obj) => Math.max(max, (obj.tdpw + obj.ovsea)), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="CER 정산총액" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend position="bottom" labelPlacement="right" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="month" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="백만"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="stacked" showTotalLabel="true" totalLabelJsFunction="'+ $p.id +'scwin.recTotalLabelHandler">'
		+ '		<series>'
		+ '			<Column2DSeries color="#FFFFFF" font-weight="bold" yField="tdpw" displayName="시화조력(백만)">'
		+ '				<fill>'
		+ '					<SolidColor color="#A2D2FF" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			<Column2DSeries color="#FFFFFF" font-weight="bold" yField="ovsea" displayName="해외(파트린드)(백만)">'
		+ '				<fill>'
		+ '					<SolidColor color="#BDE0FE" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '		</series>'
		+ '			</Column2DSet>'
		+ '			</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false"/>'
		+ '		</verticalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 7,
		text 		: `${menuNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdRecCerList, {
		fileName : `${menuNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		useDataFormat: true,
		applyDataFormat : true
	}, infoArr);
};
